#!/usr/bin/env python3
"""Aggregate per-GPU tuning JSONs into triton_mla_tuning.py.

Usage:
    python aggregate_tune.py --in-glob '/tmp/tune_out/tune_gpu*.json' \
        --out /root/vllm/mtp-long-ctx-fix/patches/triton_mla_tuning.py
"""
import argparse
import glob
import json
import datetime


HEADER_TPL = '''\
# SPDX-License-Identifier: Apache-2.0
# SPDX-FileCopyrightText: Copyright contributors to the vLLM project
#
# Auto-generated by tune_triton_mla.py — do NOT edit by hand.
# Re-generate via:
#     bash /root/vllm/mtp-long-ctx-fix/bench/run_tune.sh
# Device: sm120 (RTX 6000 Pro Blackwell), fp8 e4m3 KV, 144 SMs, 101376 B shmem
# Generated: {timestamp}
# Total (heads, max_model_len, B) entries: {n_entries}
"""
Per-(q_num_heads, max_model_len, B) best kernel config for
_fwd_grouped_kernel_stage1 on sm120 fp8 MLA.
Keys are (q_num_heads, max_model_len, B); values are dicts of kernel knobs.
Lookup falls back to the analytical heuristic if a key is not present.
"""


TUNED_KV_CONFIGS: dict[tuple[int, int, int], dict] = {{
'''

FOOTER = '''}


def lookup_config(q_num_heads: int, max_model_len: int, B: int) -> dict | None:
    """Return the tuned config dict for (heads, mml, B), else None.

    Matching policy:
      1. Exact match on (heads, mml, B).
      2. Round max_model_len DOWN to the nearest tuned bucket.
      3. Round B DOWN to the nearest tuned bucket (for the matched mml).
    """
    if (q_num_heads, max_model_len, B) in TUNED_KV_CONFIGS:
        return TUNED_KV_CONFIGS[(q_num_heads, max_model_len, B)]

    # heads must match exactly
    mmls = sorted({k[1] for k in TUNED_KV_CONFIGS if k[0] == q_num_heads})
    if not mmls:
        return None
    mml = max((m for m in mmls if m <= max_model_len), default=mmls[0])

    bs = sorted({k[2] for k in TUNED_KV_CONFIGS
                 if k[0] == q_num_heads and k[1] == mml})
    if not bs:
        return None
    b = max((x for x in bs if x <= B), default=bs[0])

    return TUNED_KV_CONFIGS.get((q_num_heads, mml, b))
'''


def main():
    ap = argparse.ArgumentParser()
    ap.add_argument("--in-glob", required=True)
    ap.add_argument("--out", required=True)
    args = ap.parse_args()

    all_results = []
    for path in sorted(glob.glob(args.in_glob)):
        with open(path) as f:
            data = json.load(f)
        print(f"{path}: {len(data)} winners")
        all_results.extend(data)

    # Deduplicate by (heads, max_model_len, B) — take best geomean.
    # Fallback to "best_ms" for backward compat with single-seq-len dumps.
    def _score(r):
        return r.get("geomean_ms", r.get("best_ms", float("inf")))
    by_key: dict[tuple[int, int, int], dict] = {}
    for r in all_results:
        k = (r["heads"], r["max_model_len"], r["B"])
        if k not in by_key or _score(r) < _score(by_key[k]):
            by_key[k] = r

    # Sort for deterministic output
    sorted_items = sorted(by_key.items())

    lines = [HEADER_TPL.format(
        timestamp=datetime.datetime.utcnow().isoformat(timespec="seconds"),
        n_entries=len(sorted_items),
    )]
    for (heads, mml, B), r in sorted_items:
        cfg = {
            "num_kv_splits": r["num_kv_splits"],
            "BLOCK_N": r["BLOCK_N"],
            "BLOCK_H": r["BLOCK_H"],
            "num_stages": r["num_stages"],
            "num_warps": r["num_warps"],
        }
        cfg_str = ", ".join(f'"{k}": {v}' for k, v in cfg.items())
        score = _score(r)
        msstr = ""
        if "ms_per_seq" in r:
            msstr = " ms=" + "/".join(f"{m:.2f}" for m in r["ms_per_seq"])
        lines.append(f'    ({heads}, {mml}, {B}): {{{cfg_str}}},'
                     f'  # geomean={score:.3f}{msstr}')
    lines.append(FOOTER)

    with open(args.out, "w") as f:
        f.write("\n".join(lines))

    print(f"\nWrote {args.out} with {len(sorted_items)} entries")

    print("\nSummary:")
    print(f"{'heads':>5} {'mml':>7} {'B':>4} | "
          f"{'splits':>6} {'BN':>3} {'BH':>3} {'ns':>2} {'nw':>2} | "
          f"{'geomean':>8}")
    for (heads, mml, B), r in sorted_items:
        print(f"{heads:>5} {mml:>7} {B:>4} | "
              f"{r['num_kv_splits']:>6} {r['BLOCK_N']:>3} "
              f"{r['BLOCK_H']:>3} {r['num_stages']:>2} {r['num_warps']:>2} | "
              f"{_score(r):>8.3f}")


if __name__ == "__main__":
    main()
